object WebAppConfig {
    // The ONLY allowed origin for the web app
    const val ALLOWED_ORIGIN = "https://myapp.example.com"

    // Allowed URL prefixes for navigation
    val ALLOWED_URL_PREFIXES = listOf(
        "https://myapp.example.com/",
        "https://cdn.example.com/"
    )

    // Maximum local storage value size (bytes)
    const val MAX_STORAGE_VALUE_SIZE = 1_048_576 // 1 MB

    // Maximum local storage key length
    const val MAX_STORAGE_KEY_LENGTH = 256

    // Allowed storage key pattern (alphanumeric, dots, underscores, hyphens)
    val STORAGE_KEY_PATTERN = Regex("^[a-zA-Z0-9._-]+$")

    // Bridge interface name exposed to JavaScript
    const val BRIDGE_INTERFACE_NAME = "NativeBridge"

    // Allowed bridge actions
    val ALLOWED_ACTIONS = setOf(
