package com.example.hybridapp

import android.content.Context
import android.content.SharedPreferences
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey

class SecureLocalStorage(context: Context) {

    private val masterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .build()

    private val prefs: SharedPreferences = EncryptedSharedPreferences.create(
        context,
        "hybrid_app_secure_prefs",
        masterKey,
        EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
        EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
    )

    fun getItem(key: String): String? {
        validateKey(key)
        return prefs.getString(key, null)
    }

    fun setItem(key: String, value: String) {
        validateKey(key)
        validateValue(value)
        prefs.edit().putString(key, value).apply()
    }

    fun removeItem(key: String) {
        validateKey(key)
        prefs.edit().remove(key).apply()
    }

    private fun validateKey(key: String) {
        require(key.length <= WebAppConfig.MAX_STORAGE_KEY_LENGTH) {
            "Storage key too long"
        }
        require(WebAppConfig.STORAGE_KEY_PATTERN.matches(key)) {
            "Storage key contains invalid characters"
        }
    }

    private fun validateValue(value: String) {
        require(value.toByteArray(Charsets.UTF_8).size <= WebAppConfig.MAX_STORAGE_VALUE_SIZE) {
            "Storage value too large"
        }
    }
}

