package com.example.hybridapp

import org.json.JSONObject

data class BridgeMessage(
    val action: String,
    val callbackId: String,
    val params: JSONObject
) {
    companion object {
        private val CALLBACK_ID_PATTERN = Regex("^[a-zA-Z0-9_-]{1,64}$")

        fun parse(json: String): BridgeMessage {
            val obj = JSONObject(json)
            val action = obj.optString("action", "")
            val callbackId = obj.optString("callbackId", "")
            val params = obj.optJSONObject("params") ?: JSONObject()

            require(action.isNotBlank()) { "Action is required" }
            require(action in WebAppConfig.ALLOWED_ACTIONS) {
                "Action '$action' is not allowed"
            }
            require(callbackId.isNotBlank()) { "callbackId is required" }
            require(CALLBACK_ID_PATTERN.matches(callbackId)) {
                "Invalid callbackId format"
            }

            return BridgeMessage(action, callbackId, params)
        }
    }
}

