package com.example.hybridapp

import android.webkit.JavascriptInterface
import android.webkit.WebView
import org.json.JSONObject

class NativeBridgeInterface(
    private val webView: WebView,
    private val handler: BridgeActionHandler
) {

    /**
     * Single entry point for all bridge calls from JavaScript.
     * JavaScript sends a JSON string with { action, callbackId, params }.
     * This validates the message and dispatches to the appropriate handler.
     */
    @JavascriptInterface
    fun postMessage(messageJson: String) {
        val message: BridgeMessage
        try {
            // Limit raw message size to prevent abuse
            if (messageJson.length > 100_000) {
                sendErrorToWeb("unknown", "Message too large")
                return
            }
            message = BridgeMessage.parse(messageJson)
        } catch (e: Exception) {
            sendErrorToWeb("unknown", "Invalid message: ${e.message}")
            return
        }

        // Verify the current URL is from our allowed origin before processing
        webView.post {
            val currentUrl = webView.url
            if (currentUrl == null || !isAllowedOrigin(currentUrl)) {
                sendErrorToWeb(message.callbackId, "Unauthorized origin")
                return@post
            }
            handler.handleAction(message)
        }
    }

    private fun isAllowedOrigin(url: String): Boolean {
        return WebAppConfig.ALLOWED_URL_PREFIXES.any { url.startsWith(it) }
    }

    private fun sendErrorToWeb(callbackId: String, error: String) {
        val sanitizedCallbackId = callbackId.replace("'", "\\'")
        val sanitizedError = error.replace("'", "\\'").replace("\n", " ")
        val js = "javascript:void(window.NativeBridgeCallback && window.NativeBridgeCallback('$sanitizedCallbackId', null, '$sanitizedError'))"
        webView.post { webView.evaluateJavascript(js, null) }
    }
}

