package com.example.hybridapp

import android.webkit.WebView
import org.json.JSONObject

class BridgeActionHandler(
    private val webView: WebView,
    private val activity: MainActivity
) {

    fun handleAction(message: BridgeMessage) {
        when (message.action) {
            "openCamera" -> activity.handleOpenCamera(message.callbackId)
            "getStorageItem" -> handleGetStorageItem(message)
            "setStorageItem" -> handleSetStorageItem(message)
            "removeStorageItem" -> handleRemoveStorageItem(message)
            "requestPushPermission" -> activity.handleRequestPushPermission(message.callbackId)
            "getPushToken" -> activity.handleGetPushToken(message.callbackId)
            else -> sendResultToWeb(message.callbackId, null, "Unknown action")
        }
    }

    private fun handleGetStorageItem(message: BridgeMessage) {
        try {
            val key = message.params.getString("key")
            val value = activity.secureStorage.getItem(key)
            val result = JSONObject().apply {
                put("value", value ?: JSONObject.NULL)
            }
            sendResultToWeb(message.callbackId, result.toString(), null)
        } catch (e: Exception) {
            sendResultToWeb(message.callbackId, null, "Failed to get item: ${e.message}")
        }
    }

    private fun handleSetStorageItem(message: BridgeMessage) {
        try {
            val key = message.params.getString("key")
            val value = message.params.getString("value")
            activity.secureStorage.setItem(key, value)
            sendResultToWeb(message.callbackId, "{\"success\":true}", null)
        } catch (e: Exception) {
            sendResultToWeb(message.callbackId, null, "Failed to set item: ${e.message}")
        }
    }

    private fun handleRemoveStorageItem(message: BridgeMessage) {
        try {
            val key = message.params.getString("key")
            activity.secureStorage.removeItem(key)
            sendResultToWeb(message.callbackId, "{\"success\":true}", null)
        } catch (e: Exception) {
            sendResultToWeb(message.callbackId, null, "Failed to remove item: ${e.message}")
        }
    }

    fun sendResultToWeb(callbackId: String, result: String?, error: String?) {
        val sanitizedCallbackId = sanitizeForJs(callbackId)
        val sanitizedResult = if (result != null) sanitizeForJs(result) else "null"
        val sanitizedError = if (error != null) "'${sanitizeForJs(error)}'" else "null"

        val resultArg = if (result != null) "'$sanitizedResult'" else "null"

        val js = "javascript:void(window.NativeBridgeCallback && window.NativeBridgeCallback('$sanitizedCallbackId', $resultArg, $sanitizedError))"
        webView.post {
            webView.evaluateJavascript(js, null)
        }
    }

    private fun sanitizeForJs(input: String): String {
        return input
            .replace("\\", "\\\\")
            .replace("'", "\\'")
            .replace("\"", "\\\"")
            .replace("\n", "\\n")
            .replace("\r", "\\r")
            .replace("\t", "\\t")
            .replace("<", "\\u003c")
            .replace(">", "\\u003e")
    }
}

