package com.example.hybridapp

import android.graphics.Bitmap
import android.net.http.SslError
import android.webkit.SslErrorHandler
import android.webkit.WebResourceError
import android.webkit.WebResourceRequest
import android.webkit.WebResourceResponse
import android.webkit.WebView
import android.webkit.WebViewClient
import android.util.Log

class SecureWebViewClient : WebViewClient() {

    companion object {
        private const val TAG = "SecureWebViewClient"
    }

    override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
        val url = request?.url?.toString() ?: return true

        // Only allow navigation to our allowed origins over HTTPS
        if (!isAllowedUrl(url)) {
            Log.w(TAG, "Blocked navigation to disallowed URL: $url")
            return true // Block navigation
        }

        return false // Allow navigation
    }

    override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
        super.onPageStarted(view, url, favicon)
        // Verify URL is still allowed when page starts loading
        if (url != null && !isAllowedUrl(url)) {
            view?.stopLoading()
            Log.w(TAG, "Stopped loading disallowed URL: $url")
        }
    }

    override fun onReceivedSslError(view: WebView?, handler: SslErrorHandler?, error: SslError?) {
        // NEVER proceed on SSL errors - always cancel
        Log.e(TAG, "SSL Error: ${error?.primaryError}. Cancelling.")
        handler?.cancel()
    }

    override fun onReceivedError(
        view: WebView?,
        request: WebResourceRequest?,
        error: WebResourceError?
    ) {
        super.onReceivedError(view, request, error)
        Log.e(TAG, "WebView error: ${error?.description} for ${request?.url}")
    }

    override fun onReceivedHttpError(
        view: WebView?,
        request: WebResourceRequest?,
        errorResponse: WebResourceResponse?
    ) {
        super.onReceivedHttpError(view, request, errorResponse)
        Log.e(TAG, "HTTP error ${errorResponse?.statusCode} for ${request?.url}")
    }

    private fun isAllowedUrl(url: String): Boolean {
        // Must be HTTPS
        if (!url.startsWith("https://")) return false
        return WebAppConfig.ALLOWED_URL_PREFIXES.any { url.startsWith(it) }
    }
}

