package com.example.hybridapp

import android.webkit.ConsoleMessage
import android.webkit.JsResult
import android.webkit.PermissionRequest
import android.webkit.WebChromeClient
import android.webkit.WebView
import android.util.Log

class SecureWebChromeClient : WebChromeClient() {

    companion object {
        private const val TAG = "SecureWebChromeClient"
    }

    override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
        // Log but don't expose to production
        Log.d(TAG, "Console: ${consoleMessage?.message()}")
        return true
    }

    override fun onJsAlert(view: WebView?, url: String?, message: String?, result: JsResult?): Boolean {
        // Block JS alerts from non-allowed origins
        if (url != null && !isAllowedOrigin(url)) {
            result?.cancel()
            return true
        }
        return super.onJsAlert(view, url, message, result)
    }

    override fun onJsConfirm(view: WebView?, url: String?, message: String?, result: JsResult?): Boolean {
        if (url != null && !isAllowedOrigin(url)) {
            result?.cancel()
            return true
        }
        return super.onJsConfirm(view, url, message, result)
    }

    override fun onPermissionRequest(request: PermissionRequest?) {
        // Only grant camera permission from allowed origins
        val origin = request?.origin?.toString() ?: ""
        if (!isAllowedOrigin(origin)) {
            request?.deny()
            return
        }

        val grantedResources = request?.resources?.filter { resource ->
            resource == PermissionRequest.RESOURCE_VIDEO_CAPTURE
        }?.toTypedArray()

        if (grantedResources != null && grantedResources.isNotEmpty()) {
            request.grant(grantedResources)
        } else {
            request?.deny()
        }
    }

    private fun isAllowedOrigin(url: String): Boolean {
        return url.startsWith(WebAppConfig.ALLOWED_ORIGIN)
    }
}

