package com.example.hybridapp

import android.Manifest
import android.app.Activity
import android.content.Intent
import android.content.pm.PackageManager
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.os.Environment
import android.provider.MediaStore
import android.util.Log
import android.webkit.CookieManager
import android.webkit.WebSettings
import android.webkit.WebView
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import com.google.firebase.messaging.FirebaseMessaging
import java.io.File
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

class MainActivity : AppCompatActivity() {

    companion object {
        private const val TAG = "MainActivity"
    }

    private lateinit var webView: WebView
    lateinit var secureStorage: SecureLocalStorage
    private lateinit var actionHandler: BridgeActionHandler

    // Camera handling
    private var cameraCallbackId: String? = null
    private var cameraImageUri: Uri? = null
    private lateinit var cameraLauncher: ActivityResultLauncher<Intent>
    private lateinit var cameraPermissionLauncher: ActivityResultLauncher<String>

    // Push notification permission
    private var pushCallbackId: String? = null
    private lateinit var pushPermissionLauncher: ActivityResultLauncher<String>

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        secureStorage = SecureLocalStorage(this)

        setupActivityResultLaunchers()
        setupWebView()
    }

    private fun setupActivityResultLaunchers() {
        cameraLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            val callbackId = cameraCallbackId ?: return@registerForActivityResult
            cameraCallbackId = null

            if (result.resultCode == Activity.RESULT_OK && cameraImageUri != null) {
                actionHandler.sendResultToWeb(
                    callbackId,
                    "{\"imageUri\":\"${cameraImageUri.toString()}\"}",
                    null
                )
            } else {
                actionHandler.sendResultToWeb(callbackId, null, "Camera cancelled or failed")
            }
        }

        cameraPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            val callbackId = cameraCallbackId ?: return@registerForActivityResult

            if (isGranted) {
                launchCamera(callbackId)
            } else {
                cameraCallbackId = null
                actionHandler.sendResultToWeb(callbackId, null, "Camera permission denied")
            }
        }

        pushPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            val callbackId = pushCallbackId ?: return@registerForActivityResult
            pushCallbackId = null

            actionHandler.sendResultToWeb(
                callbackId,
                "{\"granted\":$isGranted}",
                null
            )
        }
    }

    private fun setupWebView() {
        webView = findViewById(R.id.webView)

        // Configure WebView settings securely
        webView.settings.apply {
            // Enable JavaScript (required for our web app)
            javaScriptEnabled = true

            // Disable file access to prevent local file theft
            allowFileAccess = false
            allowFileAccessFromFileURLs = false
            allowUniversalAccessFromFileURLs = false
            allowContentAccess = false

            // Disable geolocation
            setGeolocationEnabled(false)

            // Set secure cache and storage modes
            cacheMode = WebSettings.LOAD_DEFAULT
            domStorageEnabled = true // Web app may need DOM storage

            // Disable dangerous features
            @Suppress("DEPRECATION")
            savePassword = false
            @Suppress("DEPRECATION")
            pluginState = WebSettings.PluginState.OFF

            // Set a custom user agent to identify our app
            userAgentString = "$userAgentString HybridApp/1.0"

            // Require HTTPS for mixed content
            mixedContentMode = WebSettings.MIXED_CONTENT_NEVER_ALLOW

            // Disable zoom for app-like experience
            setSupportZoom(false)
            builtInZoomControls = false
            displayZoomControls = false

            // Safe browsing
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                safeBrowsingEnabled = true
            }

            // Disable database (use our secure storage instead)
            databaseEnabled = false
        }

        // Configure cookies securely
        CookieManager.getInstance().apply {
            setAcceptCookie(true)
            setAcceptThirdPartyCookies(webView, false) // Block third-party cookies
        }

        // Disable WebView debugging in production
        WebView.setWebContentsDebuggingEnabled(BuildConfig.DEBUG)

        // Set secure clients
        webView.webViewClient = SecureWebViewClient()
        webView.webChromeClient = SecureWebChromeClient()

        // Set up the bridge
        actionHandler = BridgeActionHandler(webView, this)
        val bridgeInterface = NativeBridgeInterface(webView, actionHandler)
        webView.addJavascriptInterface(bridgeInterface, WebAppConfig.BRIDGE_INTERFACE_NAME)

        // Load the web app from our allowed origin only
        webView.loadUrl(WebAppConfig.ALLOWED_ORIGIN)
    }

    // ---- Camera Handling ----

    fun handleOpenCamera(callbackId: String) {
        cameraCallbackId = callbackId

        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA)
            == PackageManager.PERMISSION_GRANTED
        ) {
            launchCamera(callbackId)
        } else {
            cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
        }
    }

    private fun launchCamera(callbackId: String) {
        try {
            val imageFile = createImageFile()
            cameraImageUri = FileProvider.getUriForFile(
                this,
                "${applicationContext.packageName}.fileprovider",
                imageFile
            )

            val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
                putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri)
                addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION)
            }

            if (intent.resolveActivity(packageManager) != null) {
                cameraLauncher.launch(intent)
            } else {
                cameraCallbackId = null
                actionHandler.sendResultToWeb(callbackId, null, "No camera app available")
            }
        } catch (e: Exception) {
            cameraCallbackId = null
            actionHandler.sendResultToWeb(callbackId, null, "Failed to open camera: ${e.message}")
        }
    }

    private fun createImageFile(): File {
        val timestamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        val storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES)
        return File.createTempFile("IMG_${timestamp}_", ".jpg", storageDir)
    }

    // ---- Push Notification Handling ----

    fun handleRequestPushPermission(callbackId: String) {
        pushCallbackId = callbackId

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS)
                == PackageManager.PERMISSION_GRANTED
            ) {
                pushCallbackId = null
                actionHandler.sendResultToWeb(callbackId, "{\"granted\":true}", null)
            } else {
                pushPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
            }
        } else {
            // Pre-Android 13, notifications are enabled by default
            pushCallbackId = null
            actionHandler.sendResultToWeb(callbackId, "{\"granted\":true}", null)
        }
    }

    fun handleGetPushToken(callbackId: String) {
        FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
            if (task.isSuccessful) {
                val token = task.result
                actionHandler.sendResultToWeb(
                    callbackId,
                    "{\"token\":\"$token\"}",
                    null
                )
            } else {
                actionHandler.sendResultToWeb(
                    callbackId,
                    null,
                    "Failed to get push token"
                )
            }
        }
    }

    // ---- Back Navigation ----

    @Deprecated("Deprecated in Java")
    override fun onBackPressed() {
        if (webView.canGoBack()) {
            // Verify the back URL is still in our allowed origins
            val backList = webView.copyBackForwardList()
            val currentIndex = backList.currentIndex
            if (currentIndex > 0) {
                val previousUrl = backList.getItemAtIndex(currentIndex - 1).url
                if (WebAppConfig.ALLOWED_URL_PREFIXES.any { previousUrl.startsWith(it) }) {
                    webView.goBack()
                    return
                }
            }
        }
        @Suppress("DEPRECATION")
        super.onBackPressed()
    }

    override fun onDestroy() {
        // Clean up WebView
        webView.removeJavascriptInterface(WebAppConfig.BRIDGE_INTERFACE_NAME)
        webView.stopLoading()
        webView.destroy()
        super.onDestroy()
    }
}

